export type RunResult = {
  passed: number;
  total: number;
  outputs?: string[];
  passedTests?: number[];
  results?: { input: string; expected: string; actual: string; passed: boolean }[];
};

export function mockRun(
  _code: string,
  _language: string,
  sampleInputs: string[],
  sampleOutputs: string[]
): RunResult {
  // Mock implementation: randomly pass/fail for demo purposes
  // In a real implementation, this would execute the code
  const outputs: string[] = [];
  const passedTests: number[] = [];
  
  sampleInputs.forEach((input, i) => {
    const expected = sampleOutputs[i] ?? "";
    // For demo: 80% chance of passing
    const passed = Math.random() > 0.2;
    outputs.push(passed ? expected : `Wrong output for input: ${input}`);
    if (passed) {
      passedTests.push(i);
    }
  });

  return {
    passed: passedTests.length,
    total: sampleInputs.length,
    outputs,
    passedTests,
    results: sampleInputs.map((input, i) => ({
      input,
      expected: sampleOutputs[i] ?? "",
      actual: outputs[i] ?? "",
      passed: passedTests.includes(i),
    })),
  };
}
